mapper.insert:
INSERT INTO job_post_attachments (job_post_id, file_id) SELECT #{jobPostId}, id FROM files WHERE uploader_user_id = #{userId} AND file_category = 'ATTACHMENT' AND id IN
#{fileId}
ON CONFLICT (job_post_id, file_id) DO NOTHING

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM job_bookmarks
    WHERE user_id = #{userId}
      AND job_post_id = #{jobPostId}
)

mapper.delete:
DELETE FROM job_bookmarks
WHERE user_id = #{userId}
  AND job_post_id = #{jobPostId}
